const body = $json.body || $json;
const stops = Array.isArray(body.stops) ? body.stops : [];
const clean = stops.map(s => ({ code: String(s.cliente_codigo || s.code || '').trim(), lat: +s.lat, lng: +s.lng, name: String(s.name || '') })).filter(s => s.code && Number.isFinite(s.lat) && Number.isFinite(s.lng));
if (!clean.length) return [{ json: { ok: false, error: 'stops vazio ou sem coordenadas validas' } }];
const origin_lat = Number.isFinite(+body.origin_lat) ? +body.origin_lat : -23.6884;
const origin_lng = Number.isFinite(+body.origin_lng) ? +body.origin_lng : -46.6178;
const source = ['reactivation','prospect','mixed'].includes(body.source) ? body.source : 'mixed';
const user_id = String(body.user_id || '');
function km(lat1,lng1,lat2,lng2){const r=(d)=>d*Math.PI/180;const dlat=r(lat2-lat1)/2,dlng=r(lng2-lng1)/2;const a=Math.sin(dlat)*Math.sin(dlat)+Math.cos(r(lat1))*Math.cos(r(lat2))*Math.sin(dlng)*Math.sin(dlng);return 6371*2*Math.asin(Math.sqrt(a));}
const remaining = clean.slice();
let curLat = origin_lat, curLng = origin_lng, total = 0;
const ordered = [];
while (remaining.length) {
  let best = -1, bestD = Infinity;
  for (let i = 0; i < remaining.length; i++) {
    const d = km(curLat, curLng, remaining[i].lat, remaining[i].lng);
    if (d < bestD) { bestD = d; best = i; }
  }
  const nxt = remaining.splice(best, 1)[0];
  total += bestD;
  ordered.push({ seq: ordered.length + 1, cliente_codigo: nxt.code, name: nxt.name, lat: nxt.lat, lng: nxt.lng, leg_km: Math.round(bestD * 10)/10, cum_km: Math.round(total * 10)/10 });
  curLat = nxt.lat; curLng = nxt.lng;
}
const origin_str = origin_lat + ',' + origin_lng;
const wp = ordered.slice(0, -1).map(s => s.lat + ',' + s.lng).join('|');
const dest = ordered[ordered.length - 1];
const maps_url = 'https://www.google.com/maps/dir/?api=1&origin=' + origin_str + (wp ? '&waypoints=' + encodeURIComponent(wp) : '') + '&destination=' + dest.lat + ',' + dest.lng;
return [{ json: { ok: true, user_id, source, total_km: Math.round(total * 10)/10, stops: ordered, maps_url } }];

